func (q *Queries) UpdateVersionSummary(ctx context.Context, arg UpdateVersionSummaryParams) (AppVersion, error) {
	row := q.db.QueryRow(ctx, updateVersionSummary, arg.ID, arg.ChangeSummary)
	var i AppVersion
	err := row.Scan(
		&i.ID,
		&i.AppID,
		&i.VersionNumber,
		&i.SnapshotData,
		&i.SnapshotMetadata,
		&i.ChangeSummary,
		&i.CreatedBy,
		&i.CreatedAt,
	)
	return i, err
}
